        switch variant {

        

        
        case 1: return .NotInitialized(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .AlreadyRunning(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .StorageError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .CryptoError(
